// Extract image data from upload
const body = $input.first().body;
const imageData = body.image; // Base64 encoded image
const userId = body.userId;

if (!imageData) {
  throw new Error('No image data provided');
}

// Prepare for OCR processing
return {
  imageData: imageData,
  userId: userId,
  timestamp: new Date().toISOString(),
  processingId: `receipt_${Date.now()}`
};

// Mock OCR processing - In production, integrate with Google Vision API, AWS Textract, or similar
const imageData = $input.first().json.imageData;

// Simulate OCR text extraction
const mockOcrResults = [
  {
    text: "WALMART SUPERCENTER\nDATE: 2024-01-15\nTIME: 14:30\nGROCERIES\nBananas 2.99\nMilk 3.49\nBread 2.29\nEggs 4.99\nTOTAL: $13.76\nCASH PAYMENT",
    confidence: 0.95
  },
  {
    text: "STARBUCKS COFFEE\nDATE: 2024-01-15\nTIME: 08:15\nLatte Grande 5.45\nCroissant 3.25\nTOTAL: $8.70\nCARD ****1234",
    confidence: 0.92
  },
  {
    text: "SHELL GAS STATION\nDATE: 2024-01-14\nTIME: 18:45\nGASOLINE 15.5 GAL\nPRICE PER GAL: $3.299\nTOTAL: $51.13\nCREDIT CARD",
    confidence: 0.88
  }
];

// Select random mock result for demo
const selectedResult = mockOcrResults[Math.floor(Math.random() * mockOcrResults.length)];

return {
  ...($input.first().json),
  ocrText: selectedResult.text,
  confidence: selectedResult.confidence,
  status: 'ocr_completed'
};

// Parse OCR text to extract transaction details
const ocrText = $input.first().json.ocrText;
const lines = ocrText.split('\n').map(line => line.trim());

// Initialize transaction data
let transaction = {
  description: '',
  amount: 0,
  date: new Date().toISOString().split('T')[0],
  category: 'misc',
  merchant: '',
  confidence: $input.first().json.confidence
};

// Extract merchant name (usually first line)
if (lines.length > 0) {
  transaction.merchant = lines[0];
  transaction.description = lines[0];
}

// Extract date
for (const line of lines) {
  const dateMatch = line.match(/DATE:\s*(\d{4}-\d{2}-\d{2}|\d{2}\/\d{2}\/\d{4}|\d{2}-\d{2}-\d{4})/);
  if (dateMatch) {
    let dateStr = dateMatch[1];
    // Convert to YYYY-MM-DD format
    if (dateStr.includes('/')) {
      const parts = dateStr.split('/');
      dateStr = `${parts[2]}-${parts[0].padStart(2, '0')}-${parts[1].padStart(2, '0')}`;
    } else if (dateStr.includes('-') && dateStr.length === 10) {
      const parts = dateStr.split('-');
      if (parts[0].length === 2) {
        dateStr = `20${parts[2]}-${parts[0]}-${parts[1]}`;
      }
    }
    transaction.date = dateStr;
    break;
  }
}

// Extract total amount
for (const line of lines) {
  const totalMatch = line.match(/TOTAL[:\s]*\$?([\d,]+\.\d{2})/);
  if (totalMatch) {
    transaction.amount = -parseFloat(totalMatch[1].replace(',', '')); // Negative for expense
    break;
  }
}

// Determine category based on merchant
const merchantLower = transaction.merchant.toLowerCase();
if (merchantLower.includes('walmart') || merchantLower.includes('grocery') || merchantLower.includes('supermarket')) {
  transaction.category = 'food';
} else if (merchantLower.includes('starbucks') || merchantLower.includes('coffee') || merchantLower.includes('restaurant')) {
  transaction.category = 'food';
} else if (merchantLower.includes('shell') || merchantLower.includes('gas') || merchantLower.includes('fuel')) {
  transaction.category = 'transport';
} else if (merchantLower.includes('amazon') || merchantLower.includes('store') || merchantLower.includes('mall')) {
  transaction.category = 'shopping';
}

// Add processing metadata
transaction.source = 'receipt_ocr';
transaction.processingId = $input.first().json.processingId;
transaction.userId = $input.first().json.userId;

return transaction;

// Prepare success response with transaction details
const transaction = $('Parse Receipt Data').first().json;
const apiResponse = $input.first().json;

return {
  success: true,
  message: 'Receipt processed successfully',
  transaction: {
    id: apiResponse.result?.data?.id || 'generated',
    description: transaction.description,
    amount: transaction.amount,
    date: transaction.date,
    category: transaction.category,
    merchant: transaction.merchant,
    confidence: transaction.confidence,
    source: 'receipt_ocr'
  },
  processingTime: Date.now() - new Date($('Extract Image Data').first().json.timestamp).getTime()
};
